import{_ as a,c as e,o as r,ae as d}from"./chunks/framework.CDjunVez.js";const b=JSON.parse('{"title":"Manus AI 被 Meta 收購全解析：8 個月 $1 億 ARR 的秘密","description":"18,000 字深度研究：Manus AI 如何用 Claude 套殼打造 AI Agent、8 個月達 $1 億營收，最終被 Meta 數十億美元收購的完整故事。","frontmatter":{"title":"Manus AI 被 Meta 收購全解析：8 個月 $1 億 ARR 的秘密","description":"18,000 字深度研究：Manus AI 如何用 Claude 套殼打造 AI Agent、8 個月達 $1 億營收，最終被 Meta 數十億美元收購的完整故事。","date":"2025-12-30T00:00:00.000Z","author":"Clement Tang","tags":["企業研究","Manus","AI Agent","Meta併購","中國出海"],"category":"company-research","status":"published","lastModified":"2026-03-17T00:00:00.000Z"},"headers":[],"relativePath":"company-research/manus-ai/2025-12-30-manus-ai-research-meta-acquisition.md","filePath":"company-research/manus-ai/2025-12-30-manus-ai-research-meta-acquisition.md"}'),n={name:"company-research/manus-ai/2025-12-30-manus-ai-research-meta-acquisition.md"};function l(o,t,i,h,s,u){return r(),e("div",null,[...t[0]||(t[0]=[d(`<h1 id="manus-從「套殼」爭議到被-meta-收購的中國-ai-agent-出海傳奇" tabindex="-1">Manus：從「套殼」爭議到被 Meta 收購的中國 AI Agent 出海傳奇 <a class="header-anchor" href="#manus-從「套殼」爭議到被-meta-收購的中國-ai-agent-出海傳奇" aria-label="Permalink to &quot;Manus：從「套殼」爭議到被 Meta 收購的中國 AI Agent 出海傳奇&quot;">​</a></h1><blockquote><p>一家由 90 後中國創業者創立的 AI Agent 新創，憑藉「套殼」Claude 的技術、病毒式行銷策略，以及精準的出海佈局，在 8 個月內達成 1 億美元 ARR，最終被 Meta 以數十億美元收購。這是 2025 年最具話題性的 AI 併購案，也是中國科技公司成功出海的經典案例。</p></blockquote><hr><h2 id="執行摘要" tabindex="-1">執行摘要 <a class="header-anchor" href="#執行摘要" aria-label="Permalink to &quot;執行摘要&quot;">​</a></h2><h3 id="公司一句話定位" tabindex="-1">公司一句話定位 <a class="header-anchor" href="#公司一句話定位" aria-label="Permalink to &quot;公司一句話定位&quot;">​</a></h3><p>Manus 是由中國新創「蝴蝶效應」開發的通用型 AI Agent，能夠自主執行複雜任務（如撰寫程式、製作網站、深度研究），被譽為「第二個 DeepSeek」，於 2025 年 12 月被 Meta 收購。</p><h3 id="關鍵發現" tabindex="-1">關鍵發現 <a class="header-anchor" href="#關鍵發現" aria-label="Permalink to &quot;關鍵發現&quot;">​</a></h3><table tabindex="0"><thead><tr><th>面向</th><th>評估</th><th>說明</th></tr></thead><tbody><tr><td>技術創新</td><td>⭐⭐⭐</td><td>基於 Claude + Qwen 的多代理架構，非原創模型</td></tr><tr><td>產品執行力</td><td>⭐⭐⭐⭐⭐</td><td>極致的使用者體驗與任務完成能力</td></tr><tr><td>商業成長</td><td>⭐⭐⭐⭐⭐</td><td>8 個月達成 $100M ARR，史上最快</td></tr><tr><td>出海策略</td><td>⭐⭐⭐⭐⭐</td><td>從中國遷往新加坡，成功規避地緣政治風險</td></tr><tr><td>併購價值</td><td>⭐⭐⭐⭐⭐</td><td>被 Meta 以數十億美元收購，創辦人出任副總裁</td></tr></tbody></table><h3 id="核心結論" tabindex="-1">核心結論 <a class="header-anchor" href="#核心結論" aria-label="Permalink to &quot;核心結論&quot;">​</a></h3><ol><li><strong>「套殼」不是貶義詞</strong>：Manus 證明了在 AI 時代，基於頂級基礎模型（Claude、Qwen）進行應用層創新，同樣能創造巨大商業價值</li><li><strong>產品力勝過技術原創性</strong>：Manus 的成功來自極致的使用者體驗、穩定的任務執行，而非自研大模型</li><li><strong>出海是中國 AI 公司的必修課</strong>：面對美國晶片禁令與投資審查，Manus 果斷遷往新加坡，為併購鋪路</li><li><strong>Meta 的 AI Agent 野心</strong>：這是 Meta 2025 年第五起 AI 併購，祖克柏正全力打造 AI Agent 生態系統</li><li><strong>90 後創業者的逆襲</strong>：創辦人肖弘從華科大學生創業，歷經三次創業，最終登上 Meta 副總裁之位</li></ol><hr><h2 id="第一部分-公司概況" tabindex="-1">第一部分：公司概況 <a class="header-anchor" href="#第一部分-公司概況" aria-label="Permalink to &quot;第一部分：公司概況&quot;">​</a></h2><h3 id="_1-1-基本資料" tabindex="-1">1.1 基本資料 <a class="header-anchor" href="#_1-1-基本資料" aria-label="Permalink to &quot;1.1 基本資料&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td>產品名稱</td><td>Manus（拉丁文，意為「手」）</td></tr><tr><td>母公司</td><td>Butterfly Effect Technology（蝴蝶效應）</td></tr><tr><td>註冊地</td><td>開曼群島（香港、新加坡設有實體）</td></tr><tr><td>原營運總部</td><td>中國武漢/北京</td></tr><tr><td>現營運總部</td><td>新加坡（2025 年 7 月遷移）</td></tr><tr><td>成立時間</td><td>2022 年 4 月（蝴蝶效應）</td></tr><tr><td>產品上線</td><td>2025 年 3 月 6 日</td></tr><tr><td>員工人數</td><td>約 220 人（新加坡 100+，中國 120）</td></tr><tr><td>創辦人兼 CEO</td><td>肖弘（Xiao Hong，暱稱「Red」）</td></tr><tr><td>首席科學家</td><td>季逸超（Peak Ji）</td></tr><tr><td>產品負責人</td><td>張濤（Zhang Tao）</td></tr><tr><td>官方網站</td><td>manus.im</td></tr></tbody></table><h3 id="_1-2-創辦人背景-肖弘的三次創業" tabindex="-1">1.2 創辦人背景：肖弘的三次創業 <a class="header-anchor" href="#_1-2-創辦人背景-肖弘的三次創業" aria-label="Permalink to &quot;1.2 創辦人背景：肖弘的三次創業&quot;">​</a></h3><p>Manus 的成功，離不開創辦人肖弘的連續創業經歷。</p><h4 id="個人背景" tabindex="-1">個人背景 <a class="header-anchor" href="#個人背景" aria-label="Permalink to &quot;個人背景&quot;">​</a></h4><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td>出生年份</td><td>1992/1993 年</td></tr><tr><td>出生地</td><td>江西吉安遂川縣</td></tr><tr><td>教育背景</td><td>華中科技大學軟體工程系（2011-2015）</td></tr><tr><td>自述學業</td><td>「成績很差，但會找技術好的同學一起做產品」</td></tr></tbody></table><h4 id="第一次創業-夜鶯科技-2015-2024" tabindex="-1">第一次創業：夜鶯科技（2015-2024） <a class="header-anchor" href="#第一次創業-夜鶯科技-2015-2024" aria-label="Permalink to &quot;第一次創業：夜鶯科技（2015-2024）&quot;">​</a></h4><p>大學畢業後，肖弘創立武漢夜鶯科技，專注微信生態工具：</p><table tabindex="0"><thead><tr><th>產品</th><th>說明</th></tr></thead><tbody><tr><td>壹伴助手</td><td>微信公眾號管理工具</td></tr><tr><td>微伴助手</td><td>企業微信管理工具</td></tr></tbody></table><p><strong>融資歷程：</strong></p><ul><li>獲得騰訊、真格基金、明略科技等四輪融資</li><li>2020 年被明略軟體收購</li><li>2024 年 12 月，肖弘退出夜鶯科技股東行列</li></ul><h4 id="第二次創業-monica-2022-至今" tabindex="-1">第二次創業：Monica（2022-至今） <a class="header-anchor" href="#第二次創業-monica-2022-至今" aria-label="Permalink to &quot;第二次創業：Monica（2022-至今）&quot;">​</a></h4><p>2022 年，ChatGPT 爆發，肖弘敏銳捕捉到機會：</p><p><strong>關鍵動作：</strong></p><ol><li>收購當時爆紅的瀏覽器外掛「ChatGPT for Google」</li><li>將其升級為 All-in-One AI 助手「Monica」</li><li>整合 Claude、DeepSeek 等多個大模型</li><li>專注海外市場，2 年內用戶突破百萬</li></ol><p><strong>商業成績：</strong></p><ul><li>2024 年初，字節跳動曾出價 3,000 萬美元收購，被肖弘拒絕</li><li>2024 年底完成新一輪融資，估值近 1 億美元</li><li>2024 年實現盈利</li></ul><h4 id="第三次創業-manus-2025" tabindex="-1">第三次創業：Manus（2025） <a class="header-anchor" href="#第三次創業-manus-2025" aria-label="Permalink to &quot;第三次創業：Manus（2025）&quot;">​</a></h4><p>基於 Monica 的成功經驗，團隊於 2025 年 3 月推出 Manus，號稱「全球首款通用型 AI Agent」。</p><h3 id="_1-3-核心團隊" tabindex="-1">1.3 核心團隊 <a class="header-anchor" href="#_1-3-核心團隊" aria-label="Permalink to &quot;1.3 核心團隊&quot;">​</a></h3><table tabindex="0"><thead><tr><th>職位</th><th>姓名</th><th>背景</th></tr></thead><tbody><tr><td>CEO</td><td>肖弘</td><td>連續創業者，華科大畢業</td></tr><tr><td>首席科學家</td><td>季逸超（Peak Ji）</td><td>17 歲開發猛獁瀏覽器，高中輟學，前 Peak Labs 創辦人</td></tr><tr><td>產品負責人</td><td>張濤</td><td>前光年之外（王慧文創辦）產品負責人</td></tr></tbody></table><p><strong>團隊特色：</strong></p><ul><li>核心成員來自中國頂尖 AI 公司</li><li>2023 年在投資人撮合下，季逸超、張濤加入</li><li>結合了產品能力（肖弘、張濤）與技術深度（季逸超）</li></ul><h3 id="_1-4-發展里程碑" tabindex="-1">1.4 發展里程碑 <a class="header-anchor" href="#_1-4-發展里程碑" aria-label="Permalink to &quot;1.4 發展里程碑&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時間</th><th>事件</th></tr></thead><tbody><tr><td>2022 年 4 月</td><td>肖弘在北京創立蝴蝶效應</td></tr><tr><td>2022 年</td><td>收購 ChatGPT for Google，推出 Monica</td></tr><tr><td>2023 年 1 月</td><td>完成 1,000 萬美元 A 輪融資</td></tr><tr><td>2023 年</td><td>引入季逸超、張濤等核心成員</td></tr><tr><td>2024 年初</td><td>拒絕字節跳動 3,000 萬美元收購要約</td></tr><tr><td>2024 年底</td><td>Monica 估值近 1 億美元</td></tr><tr><td>2025 年 2 月</td><td>Monica 中文版內測，基於 DeepSeek R1</td></tr><tr><td>2025 年 3 月 5 日</td><td>Manus 在 X（Twitter）預告</td></tr><tr><td>2025 年 3 月 6 日</td><td>Manus 正式上線，4 分鐘 Demo 影片爆紅</td></tr><tr><td>2025 年 3 月</td><td>邀請碼炒至 999-50,000 人民幣</td></tr><tr><td>2025 年 3 月底</td><td>推出付費訂閱方案（$39/$199/月）</td></tr><tr><td>2025 年 4 月</td><td>獲 Benchmark 領投 7,500 萬美元，估值 5 億美元</td></tr><tr><td>2025 年 5 月</td><td>美國財政部審查 Benchmark 投資案</td></tr><tr><td>2025 年 5 月 13 日</td><td>Manus 開放註冊</td></tr><tr><td>2025 年 7 月</td><td>總部遷往新加坡，中國團隊裁員</td></tr><tr><td>2025 年 8 月</td><td>達成 9,000 萬美元 ARR</td></tr><tr><td>2025 年 11 月</td><td>達成 1 億美元 ARR，估值 5 億美元</td></tr><tr><td>2025 年 11 月</td><td>登上「全球最具潛力創業公司」亞洲區第一</td></tr><tr><td>2025 年 12 月 29 日</td><td>Meta 宣布收購 Manus</td></tr></tbody></table><hr><h2 id="第二部分-產品與技術分析" tabindex="-1">第二部分：產品與技術分析 <a class="header-anchor" href="#第二部分-產品與技術分析" aria-label="Permalink to &quot;第二部分：產品與技術分析&quot;">​</a></h2><h3 id="_2-1-manus-是什麼" tabindex="-1">2.1 Manus 是什麼？ <a class="header-anchor" href="#_2-1-manus-是什麼" aria-label="Permalink to &quot;2.1 Manus 是什麼？&quot;">​</a></h3><p>Manus 是一款「通用型 AI Agent」，與傳統 AI 聊天機器人的最大差異在於：</p><table tabindex="0"><thead><tr><th>特性</th><th>傳統聊天機器人（如 ChatGPT）</th><th>Manus</th></tr></thead><tbody><tr><td>互動模式</td><td>對話式問答</td><td>任務式執行</td></tr><tr><td>執行方式</td><td>使用者持續引導</td><td>自主規劃、執行、交付</td></tr><tr><td>輸出形式</td><td>文字回覆</td><td>完整成果（文件、網站、程式碼）</td></tr><tr><td>運行環境</td><td>即時回應</td><td>背景執行，完成後通知</td></tr></tbody></table><p><strong>官方定位：</strong></p><blockquote><p>「Manus 彌合思想與行動之間的鴻溝。它不只是處理資訊，更是交付完整成果。」</p></blockquote><h3 id="_2-2-核心功能" tabindex="-1">2.2 核心功能 <a class="header-anchor" href="#_2-2-核心功能" aria-label="Permalink to &quot;2.2 核心功能&quot;">​</a></h3><h4 id="任務執行能力" tabindex="-1">任務執行能力 <a class="header-anchor" href="#任務執行能力" aria-label="Permalink to &quot;任務執行能力&quot;">​</a></h4><p>Manus 能夠獨立完成複雜任務：</p><table tabindex="0"><thead><tr><th>任務類型</th><th>範例</th></tr></thead><tbody><tr><td>研究分析</td><td>深度產業研究、競品分析</td></tr><tr><td>程式開發</td><td>撰寫並執行 Python 程式碼</td></tr><tr><td>網站建置</td><td>設計並建立完整網站</td></tr><tr><td>文件製作</td><td>履歷、報告、簡報</td></tr><tr><td>數據處理</td><td>爬蟲、數據清洗、視覺化</td></tr><tr><td>自動化</td><td>瀏覽器操作、流程自動化</td></tr></tbody></table><h4 id="技術特色" tabindex="-1">技術特色 <a class="header-anchor" href="#技術特色" aria-label="Permalink to &quot;技術特色&quot;">​</a></h4><ol><li><strong>非同步執行</strong>：任務在雲端背景執行，使用者可離線，完成後發送通知</li><li><strong>虛擬電腦環境</strong>：每個任務在獨立虛擬機中執行，確保安全隔離</li><li><strong>透明介面</strong>：「Manus&#39;s Computer」讓使用者即時觀看 Agent 的操作過程</li><li><strong>多代理協作</strong>：複雜任務由多個專門 Agent 分工處理</li></ol><h3 id="_2-3-技術架構-「套殼」爭議" tabindex="-1">2.3 技術架構：「套殼」爭議 <a class="header-anchor" href="#_2-3-技術架構-「套殼」爭議" aria-label="Permalink to &quot;2.3 技術架構：「套殼」爭議&quot;">​</a></h3><p>Manus 發布後，最大的爭議在於其技術本質：<strong>它是否只是「套殼」？</strong></p><h4 id="基礎模型依賴" tabindex="-1">基礎模型依賴 <a class="header-anchor" href="#基礎模型依賴" aria-label="Permalink to &quot;基礎模型依賴&quot;">​</a></h4><p>根據首席科學家季逸超透露，Manus 的技術架構：</p><table tabindex="0"><thead><tr><th>組件</th><th>使用的模型</th></tr></thead><tbody><tr><td>核心推理引擎</td><td>Anthropic Claude 3.5/3.7 Sonnet</td></tr><tr><td>輔助模型</td><td>阿里巴巴 Qwen（經過微調）</td></tr><tr><td>工具調用</td><td>29 種內建工具</td></tr></tbody></table><p><strong>爭議焦點：</strong></p><p>有開發者透過「越獄」發現：</p><blockquote><p>「Manus 就是 Anthropic 的 Claude，加上 29 個工具。」</p></blockquote><p>這引發了關於 Manus 是否具有真正技術創新的質疑。</p><h4 id="技術創新在應用層" tabindex="-1">技術創新在應用層 <a class="header-anchor" href="#技術創新在應用層" aria-label="Permalink to &quot;技術創新在應用層&quot;">​</a></h4><p>然而，Manus 團隊的創新主要在「應用層」而非「模型層」：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Manus 技術架構                            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  應用層（Manus 創新）                                        │</span></span>
<span class="line"><span>│  ├── 多代理協調系統（Multi-Agent Orchestration）            │</span></span>
<span class="line"><span>│  ├── 任務規劃器（Planner）                                   │</span></span>
<span class="line"><span>│  ├── 記憶管理（Memory）                                      │</span></span>
<span class="line"><span>│  ├── 工具執行迴圈（Tool Execution Loop）                     │</span></span>
<span class="line"><span>│  └── 系統提示詞工程（System Prompt Engineering）             │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  模型層（第三方）                                            │</span></span>
<span class="line"><span>│  ├── Anthropic Claude 3.5/3.7 Sonnet                        │</span></span>
<span class="line"><span>│  └── Alibaba Qwen（微調版）                                  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  基礎設施                                                    │</span></span>
<span class="line"><span>│  ├── 虛擬機環境（80M+ 虛擬電腦）                             │</span></span>
<span class="line"><span>│  ├── Browser Use（開源瀏覽器自動化）                         │</span></span>
<span class="line"><span>│  └── 雲端運算資源                                            │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h4 id="「套殼到極致-就是勝利」" tabindex="-1">「套殼到極致，就是勝利」 <a class="header-anchor" href="#「套殼到極致-就是勝利」" aria-label="Permalink to &quot;「套殼到極致，就是勝利」&quot;">​</a></h4><p>中國媒體澎湃新聞的評論標題精準概括了 Manus 的策略：</p><blockquote><p>「套殼到極致，就是勝利。」</p></blockquote><p>Manus 的成功證明：在 AI 時代，<strong>不一定要自研基礎模型，應用層的創新同樣能創造巨大商業價值</strong>。</p><h3 id="_2-4-與競品比較" tabindex="-1">2.4 與競品比較 <a class="header-anchor" href="#_2-4-與競品比較" aria-label="Permalink to &quot;2.4 與競品比較&quot;">​</a></h3><h4 id="manus-vs-openai-deep-research" tabindex="-1">Manus vs OpenAI Deep Research <a class="header-anchor" href="#manus-vs-openai-deep-research" aria-label="Permalink to &quot;Manus vs OpenAI Deep Research&quot;">​</a></h4><table tabindex="0"><thead><tr><th>維度</th><th>Manus</th><th>OpenAI Deep Research</th></tr></thead><tbody><tr><td>基礎模型</td><td>Claude + Qwen</td><td>OpenAI o3</td></tr><tr><td>自主程度</td><td>高度自主</td><td>中度自主</td></tr><tr><td>單次任務成本</td><td>~$2</td><td>~$20</td></tr><tr><td>GAIA 基準測試</td><td>SOTA（最佳）</td><td>次於 Manus</td></tr><tr><td>穩定性</td><td>較低（崩潰率較高）</td><td>較高</td></tr><tr><td>執行時間</td><td>較長</td><td>較短</td></tr></tbody></table><p>MIT Technology Review 實測結論：</p><blockquote><p>「在三項任務中，Manus 有兩項表現優於 ChatGPT Deep Research，但完成時間顯著較長，且失敗率較高。」</p></blockquote><h3 id="_2-5-技術限制" tabindex="-1">2.5 技術限制 <a class="header-anchor" href="#_2-5-技術限制" aria-label="Permalink to &quot;2.5 技術限制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>說明</th></tr></thead><tbody><tr><td>穩定性不足</td><td>頻繁崩潰、系統不穩定</td></tr><tr><td>長文本處理</td><td>處理大量文本時可能出錯</td></tr><tr><td>依賴第三方模型</td><td>Claude 或 Qwen 若有變動將直接影響 Manus</td></tr><tr><td>成本控制</td><td>複雜任務消耗大量運算資源</td></tr></tbody></table><hr><h2 id="第三部分-商業模式分析" tabindex="-1">第三部分：商業模式分析 <a class="header-anchor" href="#第三部分-商業模式分析" aria-label="Permalink to &quot;第三部分：商業模式分析&quot;">​</a></h2><h3 id="_3-1-定價策略" tabindex="-1">3.1 定價策略 <a class="header-anchor" href="#_3-1-定價策略" aria-label="Permalink to &quot;3.1 定價策略&quot;">​</a></h3><p>Manus 採用 Freemium + 訂閱制：</p><table tabindex="0"><thead><tr><th>方案</th><th>月費</th><th>點數</th><th>並行任務數</th><th>特色</th></tr></thead><tbody><tr><td>Free</td><td>$0</td><td>300/日</td><td>1</td><td>基本功能</td></tr><tr><td>Plus</td><td>$39</td><td>3,900</td><td>2</td><td>進階功能</td></tr><tr><td>Pro</td><td>$199</td><td>19,900</td><td>5</td><td>優先存取、尖峰時段保障</td></tr></tbody></table><p><strong>點數消耗：</strong></p><ul><li>簡單任務：200-300 點</li><li>複雜任務：600-900 點</li></ul><h3 id="_3-2-營收成長" tabindex="-1">3.2 營收成長 <a class="header-anchor" href="#_3-2-營收成長" aria-label="Permalink to &quot;3.2 營收成長&quot;">​</a></h3><p>Manus 創下了 SaaS 史上最快達成 $100M ARR 的紀錄：</p><table tabindex="0"><thead><tr><th>時間點</th><th>ARR</th><th>距離上線</th></tr></thead><tbody><tr><td>2025 年 3 月</td><td>$0</td><td>上線</td></tr><tr><td>2025 年 8 月</td><td>$90M</td><td>5 個月</td></tr><tr><td>2025 年 11 月</td><td>$100M</td><td>8 個月</td></tr><tr><td>2025 年 12 月（併購前）</td><td>$125M+</td><td>9 個月</td></tr></tbody></table><p><strong>主要市場：</strong></p><ol><li>日本</li><li>中東</li><li>美國</li></ol><p><strong>關鍵洞察：</strong></p><blockquote><p>「海外客戶的付費意願是中國客戶的 5 倍。」（Manus 創辦團隊）</p></blockquote><h3 id="_3-3-用戶規模" tabindex="-1">3.3 用戶規模 <a class="header-anchor" href="#_3-3-用戶規模" aria-label="Permalink to &quot;3.3 用戶規模&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數據</th></tr></thead><tbody><tr><td>上線首週等待名單</td><td>200 萬人</td></tr><tr><td>Discord 社群成員</td><td>13.8 萬人（數天內）</td></tr><tr><td>月活躍用戶（首月）</td><td>2,300 萬</td></tr><tr><td>處理 Token 數</td><td>147 兆+</td></tr><tr><td>建立虛擬電腦數</td><td>8,000 萬+</td></tr></tbody></table><h3 id="_3-4-融資歷程" tabindex="-1">3.4 融資歷程 <a class="header-anchor" href="#_3-4-融資歷程" aria-label="Permalink to &quot;3.4 融資歷程&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時間</th><th>輪次</th><th>金額</th><th>估值</th><th>領投</th></tr></thead><tbody><tr><td>2022</td><td>種子</td><td>未公開</td><td>-</td><td>真格基金</td></tr><tr><td>2023 年 1 月</td><td>A 輪</td><td>$10M</td><td>未公開</td><td>紅杉中國、騰訊、真格、王慧文</td></tr><tr><td>2025 年 4 月</td><td>B 輪</td><td>$75M</td><td>$500M</td><td>Benchmark</td></tr><tr><td>2025 年 12 月</td><td>併購</td><td>數十億美元（傳）</td><td>$2B+（併購前估值）</td><td>Meta</td></tr></tbody></table><p><strong>累計融資：</strong> $85M+（併購前）</p><hr><h2 id="第四部分-成功出海的關鍵因素" tabindex="-1">第四部分：成功出海的關鍵因素 <a class="header-anchor" href="#第四部分-成功出海的關鍵因素" aria-label="Permalink to &quot;第四部分：成功出海的關鍵因素&quot;">​</a></h2><h3 id="_4-1-為何-manus-能成功出海" tabindex="-1">4.1 為何 Manus 能成功出海？ <a class="header-anchor" href="#_4-1-為何-manus-能成功出海" aria-label="Permalink to &quot;4.1 為何 Manus 能成功出海？&quot;">​</a></h3><p>作為一家中國創立的 AI 公司，Manus 的成功出海值得深入分析。</p><h4 id="因素一-產品定位瞄準全球市場" tabindex="-1">因素一：產品定位瞄準全球市場 <a class="header-anchor" href="#因素一-產品定位瞄準全球市場" aria-label="Permalink to &quot;因素一：產品定位瞄準全球市場&quot;">​</a></h4><p>從第一天起，Manus 的母產品 Monica 就專注海外市場：</p><table tabindex="0"><thead><tr><th>策略</th><th>說明</th></tr></thead><tbody><tr><td>英文優先</td><td>產品介面、文檔全面英文化</td></tr><tr><td>國際定價</td><td>$39-$199/月，符合歐美付費習慣</td></tr><tr><td>全球基礎設施</td><td>雲端服務佈建於海外</td></tr><tr><td>避開中國市場</td><td>初期不經營中國市場，避免低價競爭</td></tr></tbody></table><h4 id="因素二-病毒式行銷策略" tabindex="-1">因素二：病毒式行銷策略 <a class="header-anchor" href="#因素二-病毒式行銷策略" aria-label="Permalink to &quot;因素二：病毒式行銷策略&quot;">​</a></h4><p>Manus 的發布堪稱教科書級的病毒行銷：</p><p><strong>1. 稀缺性策略</strong></p><ul><li>採用「邀請制」，製造供不應求的氛圍</li><li>邀請碼在中國平台炒至 999-50,000 人民幣</li><li>類似早期 Gmail、Clubhouse 的策略</li></ul><p><strong>2. 高品質 Demo 影片</strong></p><ul><li>4 分鐘展示影片獲得 100 萬+ 觀看</li><li>展示 Manus 自主完成複雜任務的能力</li><li>引發 AI 圈廣泛討論</li></ul><p><strong>3. KOL 推薦</strong></p><ul><li>Twitter 創辦人 Jack Dorsey 公開讚揚</li><li>Hugging Face 產品負責人 Victor Mustar 稱其為「AGI 的一瞥」</li><li>被譽為「第二個 DeepSeek」</li></ul><h4 id="因素三-時機精準" tabindex="-1">因素三：時機精準 <a class="header-anchor" href="#因素三-時機精準" aria-label="Permalink to &quot;因素三：時機精準&quot;">​</a></h4><p>Manus 在 2025 年 3 月發布，正值：</p><ul><li>DeepSeek 剛剛震撼全球，中國 AI 受到高度關注</li><li>AI Agent 概念開始成為主流話題</li><li>OpenAI Deep Research 剛發布，市場需要替代方案</li></ul><h4 id="因素四-果斷的地緣政治應對" tabindex="-1">因素四：果斷的地緣政治應對 <a class="header-anchor" href="#因素四-果斷的地緣政治應對" aria-label="Permalink to &quot;因素四：果斷的地緣政治應對&quot;">​</a></h4><p>面對美國對中國 AI 投資的審查，Manus 採取了果斷行動：</p><p><strong>2025 年 5 月：美國財政部審查</strong></p><p>Benchmark 對 Manus 的 7,500 萬美元投資引發美國財政部審查，原因是 2023 年拜登行政命令限制美國對中國 AI 公司投資。</p><p><strong>Benchmark 的辯護：</strong></p><ol><li>Manus 本身不開發 AI 模型（使用 Claude、Qwen）</li><li>公司註冊於開曼群島，非中國大陸</li><li>最終審查通過</li></ol><p><strong>2025 年 7 月：遷往新加坡</strong></p><p>為徹底解決地緣政治風險，Manus 採取激進措施：</p><table tabindex="0"><thead><tr><th>行動</th><th>說明</th></tr></thead><tbody><tr><td>總部遷移</td><td>從中國遷至新加坡</td></tr><tr><td>核心團隊外遷</td><td>40+ 名核心技術人員移居新加坡</td></tr><tr><td>中國裁員</td><td>提供 N+3 至 2N 補償方案</td></tr><tr><td>海外招聘</td><td>新加坡薪資 $8,000-$18,000/月</td></tr><tr><td>多點佈局</td><td>在東京、加州設立辦公室</td></tr></tbody></table><p><strong>遷移的戰略考量：</strong></p><table tabindex="0"><thead><tr><th>考量</th><th>中國</th><th>新加坡</th></tr></thead><tbody><tr><td>晶片取得</td><td>受美國禁令限制</td><td>較易取得 NVIDIA 晶片</td></tr><tr><td>投資審查</td><td>受美國嚴格審查</td><td>與西方關係友善</td></tr><tr><td>企業形象</td><td>「中國 AI 公司」標籤</td><td>「新加坡科技公司」</td></tr><tr><td>人才成本</td><td>較低</td><td>較高</td></tr></tbody></table><h3 id="_4-2-「套殼」為何反而成為優勢" tabindex="-1">4.2 「套殼」為何反而成為優勢？ <a class="header-anchor" href="#_4-2-「套殼」為何反而成為優勢" aria-label="Permalink to &quot;4.2 「套殼」為何反而成為優勢？&quot;">​</a></h3><p>傳統觀念認為「套殼」是貶義詞，但 Manus 的案例顯示，在特定條件下，「套殼」反而是優勢：</p><h4 id="_1-避開模型研發的高風險" tabindex="-1">1. 避開模型研發的高風險 <a class="header-anchor" href="#_1-避開模型研發的高風險" aria-label="Permalink to &quot;1. 避開模型研發的高風險&quot;">​</a></h4><table tabindex="0"><thead><tr><th>自研大模型</th><th>應用層創新（Manus 策略）</th></tr></thead><tbody><tr><td>需要數億美元投資</td><td>投資規模較小</td></tr><tr><td>需要頂尖 AI 人才</td><td>產品人才為主</td></tr><tr><td>研發週期長（年計）</td><td>快速迭代（週計）</td></tr><tr><td>晶片需求巨大</td><td>晶片需求較低</td></tr><tr><td>受晶片禁令影響大</td><td>影響較小</td></tr></tbody></table><h4 id="_2-規避地緣政治風險" tabindex="-1">2. 規避地緣政治風險 <a class="header-anchor" href="#_2-規避地緣政治風險" aria-label="Permalink to &quot;2. 規避地緣政治風險&quot;">​</a></h4><p>由於 Manus 不開發自有 AI 模型，美國財政部最終判定其不屬於需要限制的「中國 AI 公司」範疇。</p><h4 id="_3-專注用戶價值" tabindex="-1">3. 專注用戶價值 <a class="header-anchor" href="#_3-專注用戶價值" aria-label="Permalink to &quot;3. 專注用戶價值&quot;">​</a></h4><p>將資源集中於：</p><ul><li>使用者體驗優化</li><li>任務執行穩定性</li><li>產品行銷與成長</li></ul><h3 id="_4-3-中國-ai-出海的啟示" tabindex="-1">4.3 中國 AI 出海的啟示 <a class="header-anchor" href="#_4-3-中國-ai-出海的啟示" aria-label="Permalink to &quot;4.3 中國 AI 出海的啟示&quot;">​</a></h3><p>Manus 的成功為中國 AI 公司提供了出海範本：</p><table tabindex="0"><thead><tr><th>啟示</th><th>說明</th></tr></thead><tbody><tr><td><strong>產品優先於技術</strong></td><td>不需要自研模型，應用層創新同樣有價值</td></tr><tr><td><strong>海外市場付費意願高</strong></td><td>歐美、日本、中東用戶付費意願遠高於中國</td></tr><tr><td><strong>地緣政治需早規劃</strong></td><td>預判風險，提前佈局海外實體</td></tr><tr><td><strong>新加坡是理想跳板</strong></td><td>兼具亞洲地緣優勢與西方友善關係</td></tr><tr><td><strong>開源模型降低門檻</strong></td><td>DeepSeek 等開源模型讓「套殼」更容易</td></tr></tbody></table><hr><h2 id="第五部分-meta-併購深度分析" tabindex="-1">第五部分：Meta 併購深度分析 <a class="header-anchor" href="#第五部分-meta-併購深度分析" aria-label="Permalink to &quot;第五部分：Meta 併購深度分析&quot;">​</a></h2><h3 id="_5-1-併購案概要" tabindex="-1">5.1 併購案概要 <a class="header-anchor" href="#_5-1-併購案概要" aria-label="Permalink to &quot;5.1 併購案概要&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>內容</th></tr></thead><tbody><tr><td>宣布日期</td><td>2025 年 12 月 29 日</td></tr><tr><td>收購方</td><td>Meta Platforms Inc.</td></tr><tr><td>被收購方</td><td>Butterfly Effect Technology（Manus）</td></tr><tr><td>交易金額</td><td>未公開（傳數十億美元）</td></tr><tr><td>併購前估值</td><td>~$2B（尋求融資時）</td></tr><tr><td>上一輪估值</td><td>$500M（2025 年 4 月）</td></tr><tr><td>整合方式</td><td>獨立運營 + 技術整合</td></tr><tr><td>創辦人安排</td><td>肖弘出任 Meta 副總裁</td></tr><tr><td>團隊安排</td><td>100 名成員加入 Meta 超級智慧實驗室（MSL）</td></tr><tr><td>總部</td><td>維持新加坡</td></tr></tbody></table><h3 id="_5-2-交易估值分析" tabindex="-1">5.2 交易估值分析 <a class="header-anchor" href="#_5-2-交易估值分析" aria-label="Permalink to &quot;5.2 交易估值分析&quot;">​</a></h3><p>雖然 Meta 未公開交易金額，但可從多個角度推估：</p><h4 id="估值推算" tabindex="-1">估值推算 <a class="header-anchor" href="#估值推算" aria-label="Permalink to &quot;估值推算&quot;">​</a></h4><table tabindex="0"><thead><tr><th>方法</th><th>計算</th><th>估值</th></tr></thead><tbody><tr><td>ARR 倍數（10x）</td><td>$125M × 10</td><td>$1.25B</td></tr><tr><td>ARR 倍數（20x）</td><td>$125M × 20</td><td>$2.5B</td></tr><tr><td>上輪估值成長（4x）</td><td>$500M × 4</td><td>$2B</td></tr><tr><td>媒體傳聞</td><td>「數十億美元」</td><td>$2-5B</td></tr></tbody></table><p><strong>合理估值區間：$2B - $3B</strong></p><h4 id="對比其他-ai-併購案" tabindex="-1">對比其他 AI 併購案 <a class="header-anchor" href="#對比其他-ai-併購案" aria-label="Permalink to &quot;對比其他 AI 併購案&quot;">​</a></h4><table tabindex="0"><thead><tr><th>併購案</th><th>金額</th><th>ARR 倍數</th></tr></thead><tbody><tr><td>Microsoft → Nuance</td><td>$19.7B</td><td>~15x</td></tr><tr><td>Databricks → MosaicML</td><td>$1.3B</td><td>~100x</td></tr><tr><td>Meta → Manus</td><td>$2-3B（估）</td><td>16-24x</td></tr></tbody></table><p>以 Manus 的成長速度（8 個月 $0→$100M），20x 左右的 ARR 倍數屬於合理範圍。</p><h3 id="_5-3-alexandr-wang-與-msl-併購的幕後推手" tabindex="-1">5.3 Alexandr Wang 與 MSL：併購的幕後推手 <a class="header-anchor" href="#_5-3-alexandr-wang-與-msl-併購的幕後推手" aria-label="Permalink to &quot;5.3 Alexandr Wang 與 MSL：併購的幕後推手&quot;">​</a></h3><p>這筆交易的背後，有一個關鍵人物：<strong>Alexandr Wang</strong>，Scale AI 創辦人，現任 Meta 首席 AI 長。</p><h4 id="alexandr-wang-的角色" tabindex="-1">Alexandr Wang 的角色 <a class="header-anchor" href="#alexandr-wang-的角色" aria-label="Permalink to &quot;Alexandr Wang 的角色&quot;">​</a></h4><p>2025 年 6 月，Meta 以 143 億美元收購 Scale AI 49% 股權，並聘請其創辦人 Alexandr Wang 加入 Meta 擔任首席 AI 長（Chief AI Officer），領導新成立的「Meta 超級智慧實驗室」（Meta Superintelligence Labs, MSL）。</p><p>祖克柏在內部備忘錄中寫道：</p><blockquote><p>「Alex 和我合作多年，我認為他是這一代最令人印象深刻的創辦人。」</p></blockquote><h4 id="wang-公開宣布-manus-併購" tabindex="-1">Wang 公開宣布 Manus 併購 <a class="header-anchor" href="#wang-公開宣布-manus-併購" aria-label="Permalink to &quot;Wang 公開宣布 Manus 併購&quot;">​</a></h4><p>2025 年 12 月 29 日，Wang 在 X（Twitter）上發文確認這筆交易：</p><blockquote><p>「很興奮宣布 @ManusAI 加入 Meta，幫助我們打造出色的 AI 產品！新加坡的 Manus 團隊在探索當今模型的能力邊界、建構強大的 Agent 方面是世界級的。期待與你們合作，@Red<em>Xiao</em>！」</p></blockquote><p>這則推文顯示，Wang 在這筆交易中扮演了關鍵的推動角色。作為 MSL 的負責人，他需要為 Meta 的 AI Agent 戰略尋找最佳標的，而 Manus 正是理想選擇。</p><h4 id="msl-新加坡團隊的擴張" tabindex="-1">MSL 新加坡團隊的擴張 <a class="header-anchor" href="#msl-新加坡團隊的擴張" aria-label="Permalink to &quot;MSL 新加坡團隊的擴張&quot;">​</a></h4><p>併購完成後，100 名 Manus 團隊成員將加入 MSL 的新加坡據點。這使得 MSL 新加坡成為 Meta AI 研發的重要基地，也解釋了為何 Meta 願意讓 Manus 維持在新加坡運營。</p><h3 id="_5-4-meta-的-ai-變現困境-為何急需-manus" tabindex="-1">5.4 Meta 的 AI 變現困境：為何急需 Manus <a class="header-anchor" href="#_5-4-meta-的-ai-變現困境-為何急需-manus" aria-label="Permalink to &quot;5.4 Meta 的 AI 變現困境：為何急需 Manus&quot;">​</a></h3><p>要理解 Meta 為何願意花數十億美元收購 Manus，必須先理解 Meta 在 AI 變現上面臨的結構性困境。</p><h4 id="meta-的營收結構-97-8-依賴廣告" tabindex="-1">Meta 的營收結構：97.8% 依賴廣告 <a class="header-anchor" href="#meta-的營收結構-97-8-依賴廣告" aria-label="Permalink to &quot;Meta 的營收結構：97.8% 依賴廣告&quot;">​</a></h4><p>2025 年第一季，Meta 97.8% 的營收來自數位廣告。這個數字揭示了一個殘酷的現實：<strong>Meta 幾乎完全依賴單一收入來源</strong>。</p><p>相較之下，競爭對手的營收結構更加多元：</p><p><strong>Google（Alphabet）的 AI 變現管道：</strong></p><ul><li><strong>Google Cloud（GCP）</strong>：2025 年 Q3 營收 151.5 億美元，年增 34%，可直接銷售 AI 服務</li><li><strong>Google One</strong>：訂閱制服務，可整合 Gemini 進階功能</li><li><strong>YouTube Premium</strong>：訂閱制影音服務</li><li><strong>Workspace</strong>：企業生產力套件，可嵌入 Gemini</li><li><strong>廣告業務</strong>：同樣受益於 AI 優化</li></ul><p><strong>Microsoft 的 AI 變現管道：</strong></p><ul><li><strong>Azure</strong>：雲端服務，2025 年 Q3 營收年增 40%，可直接銷售 AI 工作負載</li><li><strong>Microsoft 365 Copilot</strong>：每用戶每月 30 美元訂閱費</li><li><strong>GitHub Copilot</strong>：開發者訂閱服務</li><li><strong>Windows/Office 授權</strong>：可綁定 AI 功能</li><li><strong>企業授權</strong>：直接向企業銷售 AI 服務</li></ul><p><strong>Meta 的 AI 變現管道：</strong></p><ul><li><strong>廣告優化</strong>：AI 改善廣告投放效率</li><li><strong>就這樣，沒有了</strong></li></ul><p>這就是問題所在。Meta 沒有雲端服務（不像 AWS、Azure、GCP），沒有訂閱制生產力工具（不像 Microsoft 365），沒有直接的 AI 收入來源。</p><h4 id="_700-億美元投資-0-美元直接-ai-收入" tabindex="-1">700 億美元投資，0 美元直接 AI 收入 <a class="header-anchor" href="#_700-億美元投資-0-美元直接-ai-收入" aria-label="Permalink to &quot;700 億美元投資，0 美元直接 AI 收入&quot;">​</a></h4><p>2025 年，Meta 的資本支出達到 700-720 億美元，大部分投向 AI 基礎設施。但分析師指出一個尷尬的事實：</p><blockquote><p>「Meta 沒有直接的 AI 營收可以報告。就這麼簡單。」</p></blockquote><p>Oppenheimer 分析師在 2025 年下調 Meta 評級時寫道：</p><blockquote><p>「投資人將對『超級智慧』這個未知的營收機會感到困惑。」</p></blockquote><p>當 Meta 在 10 月提高資本支出預測時，股價單日下跌 11%。同樣的消息，卻讓亞馬遜股價飆升，因為亞馬遜有 AWS 可以直接變現 AI 投資。</p><h4 id="為何-manus-能解決這個問題" tabindex="-1">為何 Manus 能解決這個問題？ <a class="header-anchor" href="#為何-manus-能解決這個問題" aria-label="Permalink to &quot;為何 Manus 能解決這個問題？&quot;">​</a></h4><p>Manus 的價值在於它提供了 Meta 急需的東西：<strong>2C 端的 AI Agent 變現場景</strong>。</p><p><strong>1. 直接的訂閱收入</strong></p><p>Manus 已經有 1.25 億美元的年營收，來自 $39-$199/月的訂閱費。這是 Meta 從未擁有的：<strong>消費者直接為 AI 產品付費</strong>。</p><p><strong>2. 為 Meta Family Apps 創造新價值</strong></p><p>Meta 計劃將 Manus 技術整合至 WhatsApp、Instagram、Facebook。這能創造全新的使用場景：</p><ul><li><strong>WhatsApp Business Agents</strong>：商家可以部署 AI Agent 處理客服、訂單、預約</li><li><strong>Instagram 創作助手</strong>：創作者可以委託 AI 完成研究、腳本、內容規劃</li><li><strong>Facebook 自動化</strong>：社群管理、廣告優化、數據分析</li></ul><p>這些功能都可以收費，為 Meta 創造廣告之外的收入來源。</p><p><strong>3. 提升 ARPP（每用戶平均營收）</strong></p><p>Meta 最重要的指標之一是 ARPP（Average Revenue Per Person）。2025 年 Q3 達到 $14.46，年增 17.7%。Manus 的技術可以進一步提升這個數字：</p><ul><li>更長的用戶停留時間</li><li>更多的互動行為</li><li>更精準的廣告投放</li><li>新的付費功能</li></ul><p><strong>4. Reality Labs 的整合潛力</strong></p><p>Meta 的 AR 眼鏡和 VR 頭盔是另一個潛在的整合場景。想像一下：戴著 Meta 眼鏡，用語音指示 Manus 完成複雜任務。這種「AI + 穿戴裝置」的組合，可能成為未來的殺手級應用。</p><h4 id="與競爭對手的差距" tabindex="-1">與競爭對手的差距 <a class="header-anchor" href="#與競爭對手的差距" aria-label="Permalink to &quot;與競爭對手的差距&quot;">​</a></h4><p>總結 Meta 與競爭對手在 AI 變現上的差距：</p><table tabindex="0"><thead><tr><th>公司</th><th>雲端服務</th><th>訂閱產品</th><th>企業授權</th><th>直接 AI 收入</th></tr></thead><tbody><tr><td>Microsoft</td><td>Azure</td><td>365 Copilot</td><td>Office</td><td>$130 億/年</td></tr><tr><td>Google</td><td>GCP</td><td>Gemini/One</td><td>Workspace</td><td>有，未獨立揭露</td></tr><tr><td>Amazon</td><td>AWS</td><td>Prime</td><td>-</td><td>有，未獨立揭露</td></tr><tr><td><strong>Meta</strong></td><td><strong>無</strong></td><td><strong>無</strong></td><td><strong>無</strong></td><td><strong>$0</strong></td></tr></tbody></table><p>收購 Manus，是 Meta 試圖打破這個困境的重要一步。</p><h3 id="_5-5-併購動機總結" tabindex="-1">5.5 併購動機總結 <a class="header-anchor" href="#_5-5-併購動機總結" aria-label="Permalink to &quot;5.5 併購動機總結&quot;">​</a></h3><p>綜合以上分析，Meta 收購 Manus 的動機可以歸納為：</p><h4 id="_1-填補-ai-agent-能力缺口" tabindex="-1">1. 填補 AI Agent 能力缺口 <a class="header-anchor" href="#_1-填補-ai-agent-能力缺口" aria-label="Permalink to &quot;1. 填補 AI Agent 能力缺口&quot;">​</a></h4><p>Meta 在生成式 AI 領域投資巨大（2025 年資本支出 $70B+），但在 AI Agent 領域相對落後。OpenAI 有 Deep Research 和 Operator，Google 有 Gemini 整合 Android，Anthropic 有 Claude Computer Use，Microsoft 有 Copilot 整合 365。唯獨 Meta 缺乏成熟的 AI Agent 產品。</p><p>收購 Manus 讓 Meta 一次性獲得成熟的 AI Agent 產品、經驗豐富的團隊，以及 $125M+ 的營收業務。</p><h4 id="_2-強化-meta-ai-生態系統" tabindex="-1">2. 強化 Meta AI 生態系統 <a class="header-anchor" href="#_2-強化-meta-ai-生態系統" aria-label="Permalink to &quot;2. 強化 Meta AI 生態系統&quot;">​</a></h4><p>Meta 計劃將 Manus 技術整合至 WhatsApp（商務助理、客服自動化）、Instagram（內容創作、帳號管理）、Facebook（廣告優化、社群管理）、Meta AI（通用 AI Agent 能力），以及 Workplace（企業自動化）。</p><h4 id="_3-人才與技術併購" tabindex="-1">3. 人才與技術併購 <a class="header-anchor" href="#_3-人才與技術併購" aria-label="Permalink to &quot;3. 人才與技術併購&quot;">​</a></h4><p>這筆交易讓 Meta 獲得 100+ 人加入 MSL、肖弘成為 Meta 副總裁、多代理架構與工具調用系統等技術資產、數百萬付費用戶，以及全球領先的 AI Agent 市場地位。</p><h4 id="_4-2025-年-ai-併購策略的一環" tabindex="-1">4. 2025 年 AI 併購策略的一環 <a class="header-anchor" href="#_4-2025-年-ai-併購策略的一環" aria-label="Permalink to &quot;4. 2025 年 AI 併購策略的一環&quot;">​</a></h4><p>Manus 是 Meta 2025 年第六起 AI 相關併購。在此之前，Meta 已收購 Scale AI 49% 股權（數據標註）、PlayAI（AI 語音）、WaveForms（AI 音訊）、Rivos（AI 加速器）、Limitless（AI 穿戴裝置）。Manus 填補了 AI Agent 這個關鍵拼圖。</p><h4 id="_5-解決-ai-變現困境" tabindex="-1">5. 解決 AI 變現困境 <a class="header-anchor" href="#_5-解決-ai-變現困境" aria-label="Permalink to &quot;5. 解決 AI 變現困境&quot;">​</a></h4><p>最重要的是，Manus 為 Meta 提供了廣告之外的 AI 變現管道。這是 Meta 相較於 Google、Microsoft 最大的結構性劣勢，而 Manus 的訂閱模式和 2C 產品能力，正好能補足這個缺口。</p><h3 id="_5-6-manus-為何選擇被收購" tabindex="-1">5.6 Manus 為何選擇被收購？ <a class="header-anchor" href="#_5-6-manus-為何選擇被收購" aria-label="Permalink to &quot;5.6 Manus 為何選擇被收購？&quot;">​</a></h3><p>對 Manus 團隊而言，被 Meta 收購有多重考量：</p><h4 id="_1-地緣政治風險根本解決" tabindex="-1">1. 地緣政治風險根本解決 <a class="header-anchor" href="#_1-地緣政治風險根本解決" aria-label="Permalink to &quot;1. 地緣政治風險根本解決&quot;">​</a></h4><p>作為中國創立的公司，即使遷往新加坡，仍面臨：</p><ul><li>美國投資審查的不確定性</li><li>「中國公司」標籤的市場阻力</li><li>未來政策變化風險</li></ul><p>併入 Meta 後，這些風險一次性消除。</p><h4 id="_2-資源與規模" tabindex="-1">2. 資源與規模 <a class="header-anchor" href="#_2-資源與規模" aria-label="Permalink to &quot;2. 資源與規模&quot;">​</a></h4><table tabindex="0"><thead><tr><th>獨立發展</th><th>加入 Meta</th></tr></thead><tbody><tr><td>受限的算力資源</td><td>Meta 全球數據中心</td></tr><tr><td>需持續融資</td><td>充裕的財務資源</td></tr><tr><td>數千萬用戶</td><td>數十億用戶觸及</td></tr><tr><td>區域市場</td><td>全球即時覆蓋</td></tr></tbody></table><h4 id="_3-創辦人的理性選擇" tabindex="-1">3. 創辦人的理性選擇 <a class="header-anchor" href="#_3-創辦人的理性選擇" aria-label="Permalink to &quot;3. 創辦人的理性選擇&quot;">​</a></h4><p>肖弘公開聲明：</p><blockquote><p>「加入 Meta 讓我們能在更穩固、更可持續的基礎上發展，同時不改變 Manus 的運作方式和決策流程。」</p></blockquote><p>對創辦人而言：</p><ul><li>數十億美元財務回報</li><li>Meta 副總裁職位</li><li>繼續帶領 Manus 團隊</li><li>規避未來地緣政治風險</li></ul><h3 id="_5-7-併購後的整合計劃" tabindex="-1">5.7 併購後的整合計劃 <a class="header-anchor" href="#_5-7-併購後的整合計劃" aria-label="Permalink to &quot;5.7 併購後的整合計劃&quot;">​</a></h3><p>根據 Meta 公告：</p><table tabindex="0"><thead><tr><th>項目</th><th>安排</th></tr></thead><tbody><tr><td>產品運營</td><td>Manus 作為獨立產品繼續銷售</td></tr><tr><td>技術整合</td><td>逐步整合至 Meta AI 平台</td></tr><tr><td>團隊</td><td>100 人加入 MSL 新加坡團隊</td></tr><tr><td>品牌</td><td>維持 Manus 品牌</td></tr><tr><td>總部</td><td>維持新加坡</td></tr></tbody></table><p><strong>Meta 超級智慧實驗室（MSL）：</strong></p><ul><li>2025 年成立</li><li>總部位於 Menlo Park</li><li>由 Scale AI 創辦人 Alexandr Wang 領導</li><li>專注開發先進 AI 模型</li><li>新加坡為重要據點</li></ul><h3 id="_5-8-對產業的影響" tabindex="-1">5.8 對產業的影響 <a class="header-anchor" href="#_5-8-對產業的影響" aria-label="Permalink to &quot;5.8 對產業的影響&quot;">​</a></h3><h4 id="_1-驗證-ai-agent-商業價值" tabindex="-1">1. 驗證 AI Agent 商業價值 <a class="header-anchor" href="#_1-驗證-ai-agent-商業價值" aria-label="Permalink to &quot;1. 驗證 AI Agent 商業價值&quot;">​</a></h4><p>Manus 被數十億美元收購，證明了 AI Agent 作為獨立產品類別的商業可行性。</p><h4 id="_2-加速大廠-ai-agent-布局" tabindex="-1">2. 加速大廠 AI Agent 布局 <a class="header-anchor" href="#_2-加速大廠-ai-agent-布局" aria-label="Permalink to &quot;2. 加速大廠 AI Agent 布局&quot;">​</a></h4><table tabindex="0"><thead><tr><th>公司</th><th>可能動作</th></tr></thead><tbody><tr><td>Google</td><td>強化 Gemini Agent 能力</td></tr><tr><td>Microsoft</td><td>加速 Copilot Agent 開發</td></tr><tr><td>Apple</td><td>推出 Siri Agent</td></tr><tr><td>Amazon</td><td>強化 Alexa Agent</td></tr></tbody></table><h4 id="_3-中國-ai-出海模式確立" tabindex="-1">3. 中國 AI 出海模式確立 <a class="header-anchor" href="#_3-中國-ai-出海模式確立" aria-label="Permalink to &quot;3. 中國 AI 出海模式確立&quot;">​</a></h4><p>Manus 的路徑（<strong>中國研發 → 新加坡總部 → 被美國大廠收購</strong>）可能成為更多中國 AI 公司的選擇。</p><h4 id="_4-「套殼」公司估值重估" tabindex="-1">4. 「套殼」公司估值重估 <a class="header-anchor" href="#_4-「套殼」公司估值重估" aria-label="Permalink to &quot;4. 「套殼」公司估值重估&quot;">​</a></h4><p>Manus 的成功證明，即使不自研大模型，應用層創新仍可獲得高估值，這將鼓勵更多應用層新創。</p><hr><h2 id="第六部分-風險與挑戰" tabindex="-1">第六部分：風險與挑戰 <a class="header-anchor" href="#第六部分-風險與挑戰" aria-label="Permalink to &quot;第六部分：風險與挑戰&quot;">​</a></h2><h3 id="_6-1-技術風險" tabindex="-1">6.1 技術風險 <a class="header-anchor" href="#_6-1-技術風險" aria-label="Permalink to &quot;6.1 技術風險&quot;">​</a></h3><table tabindex="0"><thead><tr><th>風險</th><th>說明</th><th>影響程度</th></tr></thead><tbody><tr><td>模型依賴</td><td>依賴 Claude、Qwen，若第三方調整將受影響</td><td>高</td></tr><tr><td>穩定性問題</td><td>崩潰率較競品高</td><td>中</td></tr><tr><td>技術追趕</td><td>OpenAI、Google 正快速追趕</td><td>高</td></tr></tbody></table><h3 id="_6-2-整合風險" tabindex="-1">6.2 整合風險 <a class="header-anchor" href="#_6-2-整合風險" aria-label="Permalink to &quot;6.2 整合風險&quot;">​</a></h3><table tabindex="0"><thead><tr><th>風險</th><th>說明</th><th>影響程度</th></tr></thead><tbody><tr><td>文化衝突</td><td>中國新創 vs 美國大廠文化差異</td><td>中</td></tr><tr><td>人才流失</td><td>核心成員可能離開</td><td>中</td></tr><tr><td>產品變質</td><td>整合後可能失去靈活性</td><td>中</td></tr></tbody></table><h3 id="_6-3-地緣政治風險" tabindex="-1">6.3 地緣政治風險 <a class="header-anchor" href="#_6-3-地緣政治風險" aria-label="Permalink to &quot;6.3 地緣政治風險&quot;">​</a></h3><table tabindex="0"><thead><tr><th>風險</th><th>說明</th><th>影響程度</th></tr></thead><tbody><tr><td>中國業務</td><td>被美國公司收購後，中國市場可能受限</td><td>中</td></tr><tr><td>監管審查</td><td>其他國家可能審查此併購案</td><td>低</td></tr><tr><td>技術限制</td><td>若涉及敏感技術，可能受出口管制</td><td>低</td></tr></tbody></table><hr><h2 id="第七部分-產業啟示與結論" tabindex="-1">第七部分：產業啟示與結論 <a class="header-anchor" href="#第七部分-產業啟示與結論" aria-label="Permalink to &quot;第七部分：產業啟示與結論&quot;">​</a></h2><h3 id="_7-1-對台灣科技業的啟示" tabindex="-1">7.1 對台灣科技業的啟示 <a class="header-anchor" href="#_7-1-對台灣科技業的啟示" aria-label="Permalink to &quot;7.1 對台灣科技業的啟示&quot;">​</a></h3><h4 id="_1-ai-應用層仍有巨大機會" tabindex="-1">1. AI 應用層仍有巨大機會 <a class="header-anchor" href="#_1-ai-應用層仍有巨大機會" aria-label="Permalink to &quot;1. AI 應用層仍有巨大機會&quot;">​</a></h4><p>台灣不需要自研大模型，可以：</p><ul><li>基於開源模型（Llama、Qwen）開發垂直應用</li><li>專注特定產業場景（製造、醫療、金融）</li><li>打造符合本地需求的 AI Agent</li></ul><h4 id="_2-出海是必要選擇" tabindex="-1">2. 出海是必要選擇 <a class="header-anchor" href="#_2-出海是必要選擇" aria-label="Permalink to &quot;2. 出海是必要選擇&quot;">​</a></h4><p>台灣市場規模有限，參考 Manus 經驗：</p><ul><li>產品設計從第一天就考慮國際市場</li><li>定價策略對標歐美而非中國</li><li>新加坡可作為東南亞跳板</li></ul><h4 id="_3-「套殼」不是貶義詞" tabindex="-1">3. 「套殼」不是貶義詞 <a class="header-anchor" href="#_3-「套殼」不是貶義詞" aria-label="Permalink to &quot;3. 「套殼」不是貶義詞&quot;">​</a></h4><p>在基礎模型層，台灣難以與美國、中國競爭。但在應用層：</p><ul><li>產品體驗的優化</li><li>垂直場景的深耕</li><li>使用者需求的洞察</li></ul><p>這些都是台灣團隊可以發揮的空間。</p><h3 id="_7-2-對創業者的啟示" tabindex="-1">7.2 對創業者的啟示 <a class="header-anchor" href="#_7-2-對創業者的啟示" aria-label="Permalink to &quot;7.2 對創業者的啟示&quot;">​</a></h3><table tabindex="0"><thead><tr><th>啟示</th><th>說明</th></tr></thead><tbody><tr><td><strong>時機比技術重要</strong></td><td>Manus 在 DeepSeek 熱潮後發布，借勢成功</td></tr><tr><td><strong>行銷與產品同等重要</strong></td><td>邀請制、Demo 影片、KOL 推薦缺一不可</td></tr><tr><td><strong>地緣政治是新變數</strong></td><td>中國創業者必須提前規劃出海架構</td></tr><tr><td><strong>被併購是好結局</strong></td><td>不需要執著於獨立上市，併購同樣是成功</td></tr></tbody></table><h3 id="_7-3-結論" tabindex="-1">7.3 結論 <a class="header-anchor" href="#_7-3-結論" aria-label="Permalink to &quot;7.3 結論&quot;">​</a></h3><p>Manus 的故事，是 2025 年 AI 產業最具戲劇性的篇章之一。</p><p><strong>從技術角度看</strong>，Manus 並非革命性創新。它基於 Claude 和 Qwen 這些既有模型，透過巧妙的架構設計和產品優化，創造了優秀的 AI Agent 體驗。</p><p><strong>從商業角度看</strong>，Manus 創下了驚人紀錄。8 個月達成 1 億美元 ARR，成為史上成長最快的 SaaS 公司之一。</p><p><strong>從地緣政治角度看</strong>，Manus 展現了高度的戰略靈活性。果斷遷往新加坡，成功規避了作為「中國 AI 公司」的風險。</p><p><strong>最終結局</strong>，Meta 以數十億美元收購 Manus，創辦人肖弘成為 Meta 副總裁。這位 1992 年出生的江西小鎮青年，用三次創業證明了：</p><blockquote><p><strong>「套殼」到極致，就是勝利。</strong></p></blockquote><p>但更深層的啟示是：在 AI 時代，<strong>產品力、執行力、戰略眼光</strong>，比純粹的技術原創性更能決定成敗。</p><p>Manus 的故事還在繼續。它將如何與 Meta 整合？能否維持獨立性？會如何影響全球 AI Agent 市場？</p><p>這些問題的答案，將在 2026 年逐漸揭曉。</p><hr><h2 id="參考資料" tabindex="-1">參考資料 <a class="header-anchor" href="#參考資料" aria-label="Permalink to &quot;參考資料&quot;">​</a></h2><h3 id="官方資料" tabindex="-1">官方資料 <a class="header-anchor" href="#官方資料" aria-label="Permalink to &quot;官方資料&quot;">​</a></h3><ul><li><a href="https://manus.im" target="_blank" rel="noreferrer">Manus 官方網站</a></li><li><a href="https://manus.im/blog/manus-100m-arr" target="_blank" rel="noreferrer">Manus 官方部落格：$100M ARR 公告</a></li><li><a href="https://about.meta.com" target="_blank" rel="noreferrer">Meta 官方公告</a></li></ul><h3 id="主要新聞來源" tabindex="-1">主要新聞來源 <a class="header-anchor" href="#主要新聞來源" aria-label="Permalink to &quot;主要新聞來源&quot;">​</a></h3><ul><li><a href="https://www.bloomberg.com/news/articles/2025-12-29/meta-acquires-startup-manus-to-bolster-ai-business" target="_blank" rel="noreferrer">Bloomberg: Meta to Acquire Startup Manus</a></li><li><a href="https://www.theregister.com/2025/12/30/meta_acquires_manus/" target="_blank" rel="noreferrer">The Register: Zuck buys Chinese AI company Manus</a></li><li><a href="https://www.technologyreview.com/2025/03/11/1113133/manus-ai-review/" target="_blank" rel="noreferrer">MIT Technology Review: Everyone in AI is talking about Manus</a></li><li><a href="https://www.technologyreview.com/2025/06/05/1117958/china-ai-agent-boom/" target="_blank" rel="noreferrer">MIT Technology Review: Manus has kick-started an AI agent boom in China</a></li><li><a href="https://techcrunch.com/2025/03/31/manus-launches-paid-subscription-plans-and-a-mobile-app/" target="_blank" rel="noreferrer">TechCrunch: Manus launches paid subscription plans</a></li><li><a href="https://www.bloomberg.com/news/articles/2025-07-09/manus-quickens-shift-from-china-to-singapore-as-ai-race-heats-up" target="_blank" rel="noreferrer">Bloomberg: Manus Quickens Shift From China to Singapore</a></li></ul><h3 id="中文媒體" tabindex="-1">中文媒體 <a class="header-anchor" href="#中文媒體" aria-label="Permalink to &quot;中文媒體&quot;">​</a></h3><ul><li><a href="https://www.bnext.com.tw/article/82545/manusai-2025" target="_blank" rel="noreferrer">數位時代：中國AI黑馬Manus暴紅</a></li><li><a href="https://news.cnyes.com/news/id/5885330" target="_blank" rel="noreferrer">鉅亨網：Manus繼DS後竄紅</a></li><li><a href="https://m.thepaper.cn/newsDetail_forward_30320407" target="_blank" rel="noreferrer">澎湃新聞：Manus背后的华人团队：套壳到极致，就是胜利</a></li><li><a href="https://hub.baai.ac.cn/view/44148" target="_blank" rel="noreferrer">36Kr：對話Manus肖弘</a></li></ul><h3 id="研究報告" tabindex="-1">研究報告 <a class="header-anchor" href="#研究報告" aria-label="Permalink to &quot;研究報告&quot;">​</a></h3><ul><li><a href="https://sacra.com/research/manus-at-90m-year/" target="_blank" rel="noreferrer">Sacra: Manus at $90M/year</a></li><li><a href="https://www.chinatalk.media/p/manus-chinas-latest-ai-sensation" target="_blank" rel="noreferrer">ChinaTalk: Manus - China&#39;s Latest AI Sensation</a></li><li><a href="https://en.wikipedia.org/wiki/Manus_(AI_agent)" target="_blank" rel="noreferrer">Wikipedia: Manus (AI agent)</a></li></ul><h3 id="技術分析" tabindex="-1">技術分析 <a class="header-anchor" href="#技術分析" aria-label="Permalink to &quot;技術分析&quot;">​</a></h3><ul><li><a href="https://gist.github.com/renschni/4fbc70b31bad8dd57f3370239dccd58f" target="_blank" rel="noreferrer">GitHub: In-depth technical investigation into Manus AI agent</a></li><li><a href="https://arxiv.org/html/2505.02024v2" target="_blank" rel="noreferrer">arXiv: From Mind to Machine - The Rise of Manus AI</a></li></ul><hr><h2 id="更新記錄" tabindex="-1">更新記錄 <a class="header-anchor" href="#更新記錄" aria-label="Permalink to &quot;更新記錄&quot;">​</a></h2><table tabindex="0"><thead><tr><th>日期</th><th>更新內容</th><th>更新者</th></tr></thead><tbody><tr><td>2025-12-30</td><td>初始版本建立</td><td>Claude</td></tr></tbody></table><hr><p><em>本研究報告僅供參考，不構成任何投資建議。投資人應自行評估風險並諮詢專業顧問。</em></p>`,282)])])}const c=a(n,[["render",l]]);export{b as __pageData,c as default};
